import logging
import os

# Set up logging configuration
logging.basicConfig(filename='app.log', filemode='a', format='%(asctime)s - %(levelname)s - %(message)s')

# Configure log rotation
logging.handlers.RotatingFileHandler(filename='app.log', maxBytes=1024*1024, backupCount=5)

# Set file permissions for log files
os.chmod('app.log', 0o644)